activeEffect:
{"name": "魔法炮", "agent": "class Agent {
    get 后摇帧数() {
        const endFrames = this.currentSkillActionFrames - this.currentSkillStartupFrames
        return endFrames
    }
    get 伤害计算公式() {
        // 伤害公式本身是“字符串表达式”，这里把通用片段 vAtkP 直接嵌入，避免在 MDSL 参数里写字符串拼接
        return `(${this.vAtkP} + 100) * (100 + skill.lv * 5 + self.vit + self.str) / 100`
    }
 get 伤害标签() {
       return ["physical"];
    }
}", "definition": "root {
	/* 根据是否存在魔法炮充能buff，决定执行发射还是充能 */
	selector {
		sequence{
			condition [hasBuff,"魔法炮充能buff"]
			action [log, "魔炮发射"]
			/* 此顺序分支的以下内容仅在魔法炮充能buff存在时执行（魔炮发射） */
			action [animation,"施法前摇",$currentSkillStartupFrames]
			wait [$currentSkillStartupFrames]
			action [animation,"蓄力动画",$currentSkillChargingFrames]
			wait [$currentSkillChargingFrames]
			action [animation, "咏唱动画",$currentSkillChantingFrames]
			wait [$currentSkillChantingFrames]
			action [rangeAttack, $targetId,"physical","physical",1,$伤害计算公式,1,$伤害标签,"none",3]
			action [removeBuff,"魔法炮充能buff"]
			action [animation, "施法后摇", $后摇帧数]
			wait [$后摇帧数]
    }
		sequence{
			/* 其它顺序节点都返回失败值时，执行此分支（魔炮充填） */
			action [log, "魔炮充填"]
			action [animation,"施法前摇",$currentSkillStartupFrames]
			wait [$currentSkillStartupFrames]
			action [animation,"蓄力动画",$currentSkillChargingFrames]
			wait [$currentSkillChargingFrames]
			action [animation, "咏唱动画",$currentSkillChantingFrames]
			wait [$currentSkillChantingFrames]
			action [addBuff,"魔法炮充能buff"]
			action [animation, "施法后摇", $后摇帧数]
			wait [$后摇帧数]
    }
	}
}", "memberType": "Player"}
